import React, { useState } from "react";
import "./Calendar.css";

const Calendar = () => {
  const today = new Date();

  const [view, setView] = useState("month"); // "month" | "week"
  const [currentDate, setCurrentDate] = useState(
    new Date(today.getFullYear(), today.getMonth(), 1)
  );

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDayIndex = new Date(year, month, 1).getDay();

  const monthName = currentDate.toLocaleString("default", {
    month: "long",
    year: "numeric",
  });

  const getWeekDates = () => {
    const todayCopy = new Date();
    const day = todayCopy.getDay();
    const start = new Date(todayCopy);
    start.setDate(todayCopy.getDate() - day);

    return Array.from({ length: 7 }, (_, i) => {
      const d = new Date(start);
      d.setDate(start.getDate() + i);
      return d;
    });
  };

  const renderMonthView = () => {
    const cells = [];

    for (let i = 0; i < firstDayIndex; i++) {
      cells.push(<div key={`empty-${i}`} className="cell empty"></div>);
    }

    for (let day = 1; day <= daysInMonth; day++) {
      const isToday =
        day === today.getDate() &&
        month === today.getMonth() &&
        year === today.getFullYear();

      cells.push(
        <div key={day} className={`cell ${isToday ? "today" : ""}`}>
          {day}
        </div>
      );
    }

    return cells;
  };

  const renderWeekView = () => {
    return getWeekDates().map((date, index) => {
      const isToday =
        date.toDateString() === today.toDateString();

      return (
        <div key={index} className={`cell ${isToday ? "today" : ""}`}>
          {date.getDate()}
        </div>
      );
    });
  };

  const goPrev = () => {
    setCurrentDate(new Date(year, month - 1, 1));
  };

  const goNext = () => {
    setCurrentDate(new Date(year, month + 1, 1));
  };

  return (
    <div className="calendar-container">
      <div className="calendar-header">
        <button onClick={() => setView("month")}>Month</button>

        <div className="nav">
          <button onClick={goPrev}>Prev</button>
          <span>{monthName}</span>
          <button onClick={goNext}>Next</button>
        </div>

        <button onClick={() => setView("week")}>Week</button>
      </div>

      <div className="days-row">
        {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map((d) => (
          <div key={d} className="day-name">{d}</div>
        ))}
      </div>

      <div className="calendar-grid">
        {view === "month" ? renderMonthView() : renderWeekView()}
      </div>
    </div>
  );
};

export default Calendar;
